<?php
namespace Tests\Feature\Hr;use App\Models\LegalEntity;use App\Models\User;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Lifecycle\Actions\CompleteLifecycleTaskAction;use App\Modules\Hr\Lifecycle\Actions\HireCandidateAction;use App\Modules\Hr\Lifecycle\Actions\ManageOffboardingAction;use App\Modules\Hr\Recruitment\Actions\AdvanceApplicationAction;use App\Modules\Hr\Recruitment\Actions\CreateApplicationAction;use App\Modules\Hr\Recruitment\Actions\CreateJobPostingAction;use App\Modules\Hr\Recruitment\Actions\ManageJobOfferAction;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class LifecycleWorkflowTest extends TestCase{use RefreshHrDatabase;private User $user;protected function setUp():void{parent::setUp();(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$this->user=User::factory()->create(['role_id'=>$role]);$this->actingAs($this->user);$tenant=LegalEntity::create(['user_id'=>$this->user->id,'name'=>'Yaşam','tax_number'=>'8181818181','is_active'=>true]);app(TenantContext::class)->set($tenant);}public function test_approved_offer_creates_employee_and_7_30_60_90_tasks():void{$offer=$this->approvedOffer();$employee=app(HireCandidateAction::class)->execute($offer,['national_id'=>'12345678901']);$this->assertSame('hired',$offer->application->fresh()->status);$this->assertSame('accepted',$offer->fresh()->status);$this->assertSame(6,$employee->fresh()->onboardingChecklists()->first()->tasks()->count());$this->assertStringNotContainsString('12345678901',(string)DB::table('hr_employees')->where('id',$employee->id)->value('national_id_encrypted'));}public function test_offboarding_requires_all_tasks_before_termination():void{$employee=app(HireCandidateAction::class)->execute($this->approvedOffer(),['national_id'=>'12345678902']);$offboarding=app(ManageOffboardingAction::class)->start($employee,today()->addMonth()->toDateString(),'İstifa');try{app(ManageOffboardingAction::class)->close($offboarding);$this->fail('Açık görevlerle kapanmamalı.');}catch(\Symfony\Component\HttpKernel\Exception\HttpException $e){$this->assertSame(422,$e->getStatusCode());}foreach($offboarding->tasks as $task)app(CompleteLifecycleTaskAction::class)->execute($task,'İnsan tarafından doğrulandı.');app(ManageOffboardingAction::class)->close($offboarding->fresh());$this->assertSame('terminated',$employee->fresh()->status->value);$this->assertSame('terminated',$employee->employmentRecords()->latest('id')->first()?->status);}private function approvedOffer(){ $posting=app(CreateJobPostingAction::class)->execute(['code'=>'LIFE'.uniqid(),'title'=>'Uzman','headcount'=>1]);$application=app(CreateApplicationAction::class)->execute($posting,['first_name'=>'Yeni','last_name'=>'Çalışan','email'=>uniqid().'@example.com','consent_note'=>'Açık rıza']);$advance=app(AdvanceApplicationAction::class);foreach(['screening','interview','reference','offer'] as $stage)$application=$advance->execute($application,$stage,90,'Uygun');$offer=app(ManageJobOfferAction::class)->create($application,['gross_salary'=>60000,'proposed_start_date'=>today()->addMonth(),'expires_on'=>today()->addWeek()]);return app(ManageJobOfferAction::class)->approve($offer,'Kadro onayı');}}
